void bpnn_layerforward_openmp(float *l1, float *l2, float **conn, int n1, int n2) {
  float sum;
  int j, k;

  l1[0] = 1.0;

  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(conn, n1, n2, l1, l2) private(k, j, sum) schedule(static)
  for (j = 1; j <= n2; j++) {
    sum = 0.0;
    for (k = 0; k <= n1; k++) {	
      sum += conn[k][j] * l1[k]; 
    }
    l2[j] = squash(sum);
  }
}

void bpnn_adjust_weights_openmp(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  float new_dw;
  int k, j;
  ly[0] = 1.0;

  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(oldw, w, delta, ly) private(j, k, new_dw) schedule(static)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

void bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;   

  num_blocks = in / 16;

  printf("Performing CPU computation\n");

  // Simulate the GPU layerforward logic using OpenMP parallelization
  // The CUDA code computes sums in blocks and then aggregates them.
  // We parallelize the outer loop over hidden nodes and inner loop over input nodes.

  float *partial_sum;
  partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

  float *input_weights_one_dim;
  input_weights_one_dim = (float *) malloc((in + 1) * (hid + 1) * sizeof(float));

  int m = 0;
  for (int k = 0; k <= in; k++) {	
    for (int j = 0; j <= hid; j++) {
      input_weights_one_dim[m] = net->input_weights[k][j];
      m++;
    }
  }

  // Parallelize the computation similar to the CUDA kernel logic but using OpenMP
  // The CUDA kernel does a tree reduction in shared memory. 
  // Here we use OpenMP's reduction or just parallelize the standard dot product.
  // To match the algorithm exactly (summing weights * inputs), we can just parallelize the standard loop.

  omp_set_num_threads(NUM_THREAD);
  #pragma omp parallel for shared(net, in, hid, input_weights_one_dim) private(j, k, m, sum) schedule(static)
  for (int j = 1; j <= hid; j++) {
    sum = 0.0;
    for (int k = 0; k <= in; k++) {
      sum += net->input_weights[k][j] * net->input_units[k];
    }
    net->hidden_units[j] = squash(sum);
  }

  free(partial_sum);
  free(input_weights_one_dim);

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);  
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  bpnn_adjust_weights_openmp(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}
